/* ============================================
   AIFORGE - Enhanced Animations & Effects
   Premium Improvements v2.0
   ============================================ */

/* ============================================
   1. FLOATING PARTICLES BACKGROUND
   ============================================ */
.particles-container {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
    z-index: 0;
    overflow: hidden;
}

.particle {
    position: absolute;
    width: 4px;
    height: 4px;
    background: var(--primary-color, #6366f1);
    border-radius: 50%;
    opacity: 0.3;
    animation: floatParticle 15s infinite ease-in-out;
}

.particle:nth-child(1) { left: 10%; animation-delay: 0s; animation-duration: 12s; }
.particle:nth-child(2) { left: 20%; animation-delay: 2s; animation-duration: 14s; }
.particle:nth-child(3) { left: 30%; animation-delay: 4s; animation-duration: 16s; }
.particle:nth-child(4) { left: 40%; animation-delay: 1s; animation-duration: 13s; }
.particle:nth-child(5) { left: 50%; animation-delay: 3s; animation-duration: 15s; }
.particle:nth-child(6) { left: 60%; animation-delay: 5s; animation-duration: 11s; }
.particle:nth-child(7) { left: 70%; animation-delay: 2s; animation-duration: 17s; }
.particle:nth-child(8) { left: 80%; animation-delay: 4s; animation-duration: 14s; }
.particle:nth-child(9) { left: 90%; animation-delay: 1s; animation-duration: 12s; }

@keyframes floatParticle {
    0%, 100% {
        transform: translateY(100vh) scale(0);
        opacity: 0;
    }
    10% {
        opacity: 0.5;
        transform: translateY(90vh) scale(1);
    }
    90% {
        opacity: 0.3;
        transform: translateY(10vh) scale(0.8);
    }
    100% {
        transform: translateY(0) scale(0);
        opacity: 0;
    }
}

/* ============================================
   2. ENHANCED CARD HOVER EFFECTS
   ============================================ */
.service-card,
.feature-card,
.team-card,
.blog-card,
.portfolio-item {
    position: relative;
    overflow: hidden;
    transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

.service-card::before,
.feature-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg, transparent, rgba(99, 102, 241, 0.1), transparent);
    transition: left 0.5s ease;
}

.service-card:hover::before,
.feature-card:hover::before {
    left: 100%;
}

.service-card:hover,
.feature-card:hover {
    transform: translateY(-10px) scale(1.02);
    box-shadow: 0 25px 50px rgba(99, 102, 241, 0.2);
}

/* ============================================
   3. GLOWING BORDER EFFECT
   ============================================ */
.glow-border {
    position: relative;
}

.glow-border::after {
    content: '';
    position: absolute;
    top: -2px;
    left: -2px;
    right: -2px;
    bottom: -2px;
    background: linear-gradient(45deg, #6366f1, #8b5cf6, #ec4899, #6366f1);
    background-size: 400% 400%;
    border-radius: inherit;
    z-index: -1;
    opacity: 0;
    transition: opacity 0.3s ease;
    animation: gradientShift 3s ease infinite;
}

.glow-border:hover::after {
    opacity: 1;
}

@keyframes gradientShift {
    0%, 100% { background-position: 0% 50%; }
    50% { background-position: 100% 50%; }
}

/* ============================================
   4. SCROLL REVEAL ANIMATIONS
   ============================================ */
.reveal {
    opacity: 0;
    transform: translateY(50px);
    transition: all 0.8s cubic-bezier(0.5, 0, 0, 1);
}

.reveal.visible {
    opacity: 1;
    transform: translateY(0);
}

.reveal-left {
    opacity: 0;
    transform: translateX(-50px);
    transition: all 0.8s cubic-bezier(0.5, 0, 0, 1);
}

.reveal-left.visible {
    opacity: 1;
    transform: translateX(0);
}

.reveal-right {
    opacity: 0;
    transform: translateX(50px);
    transition: all 0.8s cubic-bezier(0.5, 0, 0, 1);
}

.reveal-right.visible {
    opacity: 1;
    transform: translateX(0);
}

.reveal-scale {
    opacity: 0;
    transform: scale(0.8);
    transition: all 0.8s cubic-bezier(0.5, 0, 0, 1);
}

.reveal-scale.visible {
    opacity: 1;
    transform: scale(1);
}

/* Staggered animation for children */
.stagger-children > * {
    opacity: 0;
    transform: translateY(30px);
    transition: all 0.5s ease;
}

.stagger-children.visible > *:nth-child(1) { transition-delay: 0.1s; }
.stagger-children.visible > *:nth-child(2) { transition-delay: 0.2s; }
.stagger-children.visible > *:nth-child(3) { transition-delay: 0.3s; }
.stagger-children.visible > *:nth-child(4) { transition-delay: 0.4s; }
.stagger-children.visible > *:nth-child(5) { transition-delay: 0.5s; }
.stagger-children.visible > *:nth-child(6) { transition-delay: 0.6s; }

.stagger-children.visible > * {
    opacity: 1;
    transform: translateY(0);
}

/* ============================================
   5. BUTTON ENHANCEMENTS
   =============================

/**
 * CRITICAL FIX FOR GRADIENT GLITCH
 * This file removes all unwanted pseudo-elements that create visual artifacts
 * Load this file AFTER style.css
 *
 * IMPORTANT: This file uses !important on EVERYTHING to override any other CSS
 */

/* =====================================================
   NUCLEAR OPTION - REMOVE ALL PSEUDO ELEMENTS
   ===================================================== */

/* REMOVE ALL ::before and ::after from ANY element with text-gradient class */
.text-gradient::before,
.text-gradient::after,
span.text-gradient::before,
span.text-gradient::after,
div.text-gradient::before,
div.text-gradient::after,
h1.text-gradient::before,
h1.text-gradient::after,
h2.text-gradient::before,
h2.text-gradient::after,
h3.text-gradient::before,
h3.text-gradient::after,
*[class*="text-gradient"]::before,
*[class*="text-gradient"]::after {
    display: none !important;
    content: "" !important;
    background: none !important;
    background-image: none !important;
    background-color: transparent !important;
    border: none !important;
    width: 0 !important;
    height: 0 !important;
    opacity: 0 !important;
    visibility: hidden !important;
    position: absolute !important;
    top: 0 !important;
    left: 0 !important;
    overflow: hidden !important;
}

/* FORCE REMOVE from sections - EVERY POSSIBLE SELECTOR */
.section-3d-cards .text-gradient::before,
.section-3d-cards .text-gradient::after,
.section-3d-cards .text-center .text-gradient::before,
.section-3d-cards .text-center .text-gradient::after,
.section-3d-cards span.text-gradient::before,
.section-3d-cards span.text-gradient::after,
.section-3d-cards div.text-gradient::before,
.section-3d-cards div.text-gradient::after,
section .text-gradient::before,
section .text-gradient::after,
section span::before,
section span::after {
    display: none !important;
    content: none !important;
    background: none !important;
    background-image: none !important;
    border: none !important;
    width: 0 !important;
    height: 0 !important;
}

/* FORCE REMOVE from headers - EVERY POSSIBLE SELECTOR */
header .text-gradient::before,
header .text-gradient::after,
header span.text-gradient::before,
header span.text-gradient::after,
header div.text-gradient::before,
header div.text-gradient::after,
header h1 .text-gradient::before,
header h1 .text-gradient::after,
header h2 .text-gradient::before,
header h2 .text-gradient::after,
header span::before,
header span::after,
header div::before,
header div::after,
header h1::before,
header h1::after,
header h2::before,
header h2::after {
    display: none !important;
    content: none !important;
    background: none !important;
    background-image: none !important;
    background-color: transparent !important;
    border: none !important;
    width: 0 !important;
    height: 0 !important;
    opacity: 0 !important;
}

/* SPECIFICALLY target the problematic rule by class combination */
.section-3d-cards .text-center .text-gradient::after,
.text-center .text-gradient::after,
.af-container .text-gradient::after {
    display: none !important;
    content: "" !important;
    background: none !important;
    background-image: none !important;
    width: 0 !important;
    height: 0 !important;
    transform: none !important;
    animation: none !important;
}

/* Clean ALL spans everywhere that might have pseudo-elements */
.section-3d-cards span::before,
.section-3d-cards span::after,
header span::before,
header span::after,
.af-container span::before,
.af-container span::after,
.text-center span::before,
.text-center span::after {
    display: none !important;
    content: none !important;
    background: none !important;
    background-image: none !important;
}

/* Remove from h1, h2 inside text-gradient contexts */
h1 span.text-gradient::before,
h1 span.text-gradient::after,
h2 span.text-gradient::before,
h2 span.text-gradient::after {
    display: none !important;
    content: "" !important;
}

/* Disable ALL animations on pseudo-elements in these areas */
header *::before,
header *::after,
.section-3d-cards *::before,
.section-3d-cards *::after {
    animation: none !important;
    transition: none !important;
}

