// ==========================================
// CARDS 3D
// ========================

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  font-family: "Inter", sans-serif;
  background-color: #0f0f23;
  color: #ffffff;
  line-height: 1.7;
  overflow-x: hidden;
}

h1, h2, h3, h4, h5, h6 {
  font-family: "Space Grotesk", sans-serif;
  font-weight: 700;
  line-height: 1.3;
  margin-bottom: 1rem;
}

h1 {
  font-size: 3.5rem;
}

h2 {
  font-size: 2.5rem;
}

h3 {
  font-size: 1.75rem;
}

h4 {
  font-size: 1.25rem;
}

p {
  color: #a1a1aa;
  margin-bottom: 1rem;
}

a {
  color: #8b5cf6;
  text-decoration: none;
  transition: all 0.3s ease;
}
a:hover {
  color: #a78bfa;
}

img {
  max-width: 100%;
  height: auto;
}

.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 15px;
}

.preloader {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: #070714;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 99999;
}
.preloader .loader {
  width: 60px;
  height: 60px;
  border: 3px solid rgba(139, 92, 246, 0.2);
  border-top-color: #8b5cf6;
  border-radius: 50%;
  animation: spin 1s linear infinite;
}
.preloader .loader::after {
  content: "";
  position: absolute;
  width: 40px;
  height: 40px;
  border: 3px solid rgba(236, 72, 153, 0.2);
  border-bottom-color: #ec4899;
  border-radius: 50%;
  animation: spin 0.8s linear infinite reverse;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}
.top-bar {
  background: #070714;
  padding: 10px 0;
  border-bottom: 1px solid rgba(139, 92, 246, 0.1);
  font-size: 0.875rem;
}
.top-bar .contact-info {
  display: flex;
  gap: 25px;
}
.top-bar .contact-info span {
  color: #a1a1aa;
}
.top-bar .contact-info span i {
  color: #8b5cf6;
  margin-right: 8px;
}
.top-bar .top-links {
  display: flex;
  align-items: center;
  gap: 20px;
}
.top-bar .top-links a {
  color: #a1a1aa;
  font-size: 0.875rem;
}
.top-bar .top-links a:hover {
  color: #8b5cf6;
}
.top-bar .top-links .social-links {
  display: flex;
  gap: 12px;
  margin-left: 15px;
}
.top-bar .top-links .social-links a {
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(139, 92, 246, 0.1);
  border-radius: 50%;
}
.top-bar .top-links .social-links a:hover {
  background: #8b5cf6;
  color: #ffffff;
}

.navbar-main {
  background: transparent;
  padding: 15px 0;
  transition: all 0.3s ease;
}
.navbar-main.scrolled {
  background: rgba(7, 7, 20, 0.95);
  backdrop-filter: blur(10px);
  box-shadow: 0 5px 30px rgba(0, 0, 0, 0.3);
  padding: 10px 0;
}
.navbar-main .navbar-brand {
  font-family: "Space Grotesk", sans-serif;
  font-size: 1.75rem;
  font-weight: 700;
  color: #ffffff;
}
.navbar-main .navbar-brand .brand-icon {
  width: 45px;
  height: 45px;
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-right: 10px;
}
.navbar-main .navbar-brand .brand-icon i {
  font-size: 1.5rem;
  color: #ffffff;
}
.navbar-main .navbar-brand span {
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.navbar-main .nav-link {
  color: #ffffff;
  font-weight: 500;
  padding: 10px 18px;
  margin: 0 3px;
  border-radius: 12px;
  transition: all 0.3s ease;
}
.navbar-main .nav-link:hover, .navbar-main .nav-link.active {
  color: #8b5cf6;
  background: rgba(139, 92, 246, 0.1);
}
.navbar-main .dropdown-menu {
  background: #1a1a2e;
  border: 1px solid rgba(139, 92, 246, 0.2);
  border-radius: 12px;
  padding: 10px;
}
.navbar-main .dropdown-menu .dropdown-item {
  color: #a1a1aa;
  padding: 10px 15px;
  border-radius: 8px;
}
.navbar-main .dropdown-menu .dropdown-item:hover {
  background: rgba(139, 92, 246, 0.1);
  color: #8b5cf6;
}
.navbar-main .btn-quote {
  background: linear-gradient(135deg, #8b5cf6 0%, #ec4899 100%);
  color: #ffffff;
  padding: 12px 28px;
  border-radius: 50px;
  font-weight: 600;
  border: none;
}
.navbar-main .btn-quote:hover {
  transform: translateY(-2px);
  box-shadow: 0 0 20px rgba(139, 92, 246, 0.3), 0 0 40px rgba(139, 92, 246, 0.1);
}
.navbar-main .phone-info {
  text-align: right;
  margin-right: 20px;
}
.navbar-main .phone-info small {
  color: #a1a1aa;
  font-size: 0.75rem;
}
.navbar-main .phone-info strong {
  display: block;
  color: #ffffff;
  font-size: 1.1rem;
}
.navbar-main .phone-info strong i {
  color: #8b5cf6;
  margin-right: 5px;
}

