// ==========================================
// VARIABLES
// ==========================================
$primary-color: #8b5cf6;
$primary-dark: #7c3aed;
$primary-light: #a78bfa;
$secondary-color: #ec4899;
$accent-color: #06b6d4;
$success-color: #10b981;
$warning-color: #f59e0b;
$danger-color: #ef4444;

$bg-dark: #0f0f23;
$bg-darker: #070714;
$bg-card: #1a1a2e;
$bg-card-hover: #252542;

$text-light: #ffffff;
$text-muted: #a1a1aa;
$text-gray: #71717a;

$gradient-primary: linear-gradient(135deg, $primary-color 0%, $secondary-color 100%);
$gradient-secondary: linear-gradient(135deg, $accent-color 0%, $primary-color 100%);
$gradient-hero: linear-gradient(135deg, rgba(139, 92, 246, 0.1) 0%, rgba(236, 72, 153, 0.1) 100%);

$font-primary: 'Space Grotesk', sans-serif;
$font-secondary: 'Inter', sans-serif;

$border-radius: 12px;
$border-radius-lg: 20px;
$transition: all 0.3s ease;

// ==========================================
// MIXINS
// ==========================================
@mixin flex-center {
    display: flex;
    align-items: center;
    justify-content: center;
}

@mixin glass-effect {
    background: rgba(26, 26, 46, 0.8);
    backdrop-filter: blur(10px);
    border: 1px solid rgba(139, 92, 246, 0.2);
}

@mixin glow-effect($color) {
    box-shadow: 0 0 20px rgba($color, 0.3), 0 0 40px rgba($color, 0.1);
}

@mixin gradient-text {
    background: $gradient-primary;
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

// ==========================================
// BASE STYLES
// ==========================================
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    scroll-behavior: smooth;
}

body {
    font-family: $font-secondary;
    background-color: $bg-dark;
    color: $text-light;
    line-height: 1.7;
    overflow-x: hidden;
}

h1, h2, h3, h4, h5, h6 {
    font-family: $font-primary;
    font-weight: 700;
    line-height: 1.3;
    margin-bottom: 1rem;
}

h1 { font-size: 3.5rem; }
h2 { font-size: 2.5rem; }
h3 { font-size: 1.75rem; }
h4 { font-size: 1.25rem; }

p {
    color: $text-muted;
    margin-bottom: 1rem;
}

a {
    color: $primary-color;
    text-decoration: none;
    transition: $transition;

    &:hover {
        color: $primary-light;
    }
}

img {
    max-width: 100%;
    height: auto;
}

.container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 15px;
}

// ==========================================
// PRELOADER
// ==========================================
.preloader {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: $bg-darker;
    @include flex-center;
    z-index: 99999;

    .loader {
        width: 60px;
        height: 60px;
        border: 3px solid rgba($primary-color, 0.2);
        border-top-color: $primary-color;
        border-radius: 50%;
        animation: spin 1s linear infinite;

        &::after {
            content: '';
            position: absolute;
            width: 40px;
            height: 40px;
            border: 3px solid rgba($secondary-color, 0.2);
            border-bottom-color: $secondary-color;
            border-radius: 50%;
            animation: spin 0.8s linear infinite reverse;
        }
    }
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

// ==========================================
// TOP BAR
// ==========================================
.top-bar {
    background: $bg-darker;
    padding: 10px 0;
    border-bottom: 1px solid rgba($primary-color, 0.1);
    font-size: 0.875rem;

    .contact-info {
        display: flex;
        gap: 25px;

        span {
            color: $text-muted;

            i {
                color: $primary-color;
                margin-right: 8px;
            }
        }
    }

    .top-links {
        display: flex;
        align-items: center;
        gap: 20px;

        a {
            color: $text-muted;
            font-size: 0.875rem;

            &:hover {
                color: $primary-color;
            }
        }

        .social-links {
            display: flex;
            gap: 12px;
            margin-left: 15px;

            a {
                width: 32px;
                height: 32px;
                @include flex-center;
                background: rgba($primary-color, 0.1);
                border-radius: 50%;

                &:hover {
                    background: $primary-color;
                    color: $text-light;
                }
            }
        }
    }
}

